package ru.memearena.meme.api; import org.springframework.context.annotation.Profile; import org.springframework.web.bind.annotation.*; import ru.memearena.meme.application.MemeService; import java.util.UUID; @Profile({"local","test"}) @RestController @RequestMapping("/api/v1/local/memes") public class LocalMemeModerationController { private final MemeService service; public LocalMemeModerationController(MemeService service){this.service=service;} @PostMapping("/{memeId}/approve") public MemeResponse approve(@PathVariable UUID memeId){return MemeResponse.from(service.approve(memeId));} @PostMapping("/{memeId}/reject") public MemeResponse reject(@PathVariable UUID memeId){return MemeResponse.from(service.reject(memeId));} }
